import { NavLink, Outlet, Navigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

export default function UserLayout() {
  const { user, logout } = useAuth();

  if (!user) return <Navigate to="/login" replace />;

  return (
    <div style={styles.wrapper}>
      <aside style={styles.sidebar}>
        <div style={styles.brand}>👤 {user.full_name}</div>
        <nav style={styles.nav}>
          <NavLink to="/orders"  style={navStyle}>📦 Đơn hàng của tôi</NavLink>
          <NavLink to="/profile" style={navStyle}>⚙️ Quản lý tài khoản</NavLink>
        </nav>
        <button onClick={logout} style={styles.btnLogout}>🚪 Đăng xuất</button>
      </aside>

      <main style={styles.main}>
        <Outlet />
      </main>
    </div>
  );
}

const navStyle = ({ isActive }) => ({
  display: 'block', padding: '10px 14px', marginBottom: 4,
  borderRadius: 6, textDecoration: 'none', fontWeight: 500,
  background: isActive ? '#dc2626' : 'transparent',
  color: isActive ? '#fff' : '#374151',
});

const styles = {
  wrapper:   { display: 'flex', minHeight: '100vh', fontFamily: 'sans-serif' },
  sidebar:   { width: 220, background: '#f9fafb', borderRight: '1px solid #e5e7eb',
               display: 'flex', flexDirection: 'column', padding: 16 },
  brand:     { fontWeight: 700, fontSize: 14, padding: '12px 4px 16px',
               borderBottom: '1px solid #e5e7eb', marginBottom: 12, color: '#111' },
  nav:       { flex: 1 },
  btnLogout: { background: 'none', border: '1px solid #dc2626', color: '#dc2626',
               borderRadius: 6, padding: '8px 0', cursor: 'pointer', marginTop: 'auto' },
  main:      { flex: 1, padding: 32, background: '#fff' },
};
